return facts.map(f => ({ json: f }));

// ═══════════════════════════════════════════════════════
// Step 3: Build RAG Request gegen ERGO Collection
// Die Query ist so formuliert, dass sie die ERGO-AVB
// nach dem jeweiligen Aspekt durchsucht
// ═══════════════════════════════════════════════════════
const fact = $input.item.json;
const ERGO_COLLECTION = '32c26a09-6c8c-449c-a060-1146f20c0322';

return {
  ...fact,
  retrievalRequestBody: JSON.stringify({
    collection_names: [ERGO_COLLECTION],
    query: fact.rag_query,
    k: 5
  })
};

// ═══════════════════════════════════════════════════════
// Step 5: Parse RAG + Build LLM Comparison Request
// WICHTIG: Das LLM soll die ERGO-Infos AUS DEM RAG
// extrahieren, NICHT aus hardcoded Daten
// ═══════════════════════════════════════════════════════
const ragResp = $input.item.json;
const fact = $('03 - Build RAG Request').item.json;

const docs = ragResp.documents?.[0] || [];
const metas = ragResp.metadatas?.[0] || [];
const dists = ragResp.distances?.[0] || [];

const contextChunks = docs.map((text, i) => {
  const meta = metas[i] || {};
  const source = (meta.name || meta.source || 'Unbekannt')
    .replace(/\.md\.txt$|\.txt$|\.md$/gi, '').replace(/_/g, ' ').trim();
  const dist = dists[i] || 'N/A';
  return '### Chunk ' + (i+1) + ' (Quelle: ' + source + ', Distance: ' + (typeof dist === 'number' ? dist.toFixed(3) : dist) + ')\n' + text;
}).join('\n\n');

const systemPrompt = 'Du bist ein Versicherungsexperte, der AVB (Allgemeine Versicherungsbedingungen) analysiert und vergleicht.\n\nDeine Aufgabe: Analysiere die bereitgestellten ERGO AVB-Dokumente zu einem bestimmten Aspekt und vergleiche das Ergebnis mit der HanseMerkur Seminar-Ruecktrittsversicherung.\n\n## WICHTIGE REGELN:\n1. Extrahiere die ERGO-Informationen AUSSCHLIEssLICH aus den bereitgestellten RAG-Dokumenten\n2. Wenn die Dokumente KEINE Information zu diesem Aspekt enthalten, schreibe klar: "In den vorliegenden ERGO AVB wurde hierzu keine Regelung gefunden."\n3. ERFINDE KEINE Informationen - nur was in den Dokumenten steht\n4. Sei praezise: Nenne konkrete Betraege, Prozentsaetze, Bedingungen, Paragraphen\n5. Zitiere relevante Passagen aus den Dokumenten\n6. Bewerte am Ende: Welcher Anbieter bietet hier den besseren Schutz? (HMR besser / ERGO besser / gleichwertig / nicht vergleichbar)\n7. Antworte auf Deutsch in strukturierter Form\n\n## Bereitgestellte ERGO AVB-Dokumente:\n' + contextChunks;

const userPrompt = 'Analysiere und vergleiche folgenden Aspekt:\n\n**Kategorie:** ' + fact.kategorie + '\n**Aspekt:** ' + fact.aspekt + '\n\n**HanseMerkur (HMR) Regelung:**\n' + fact.hmr + '\n\n**Frage an die ERGO AVB:**\n' + fact.rag_query + '\n\nBitte:\n1. Was genau sagen die ERGO AVB-Dokumente zu diesem Aspekt? Zitiere relevante Stellen.\n2. Fasse die ERGO-Regelung in 1-3 Saetzen zusammen\n3. Vergleiche mit der HMR-Regelung: Was sind die konkreten Unterschiede?\n4. Bewertung: Wer bietet den besseren Schutz fuer diesen Aspekt?';

return {
  ...fact,
  ragContext: contextChunks,
  ragChunkCount: docs.length,
  ragDistances: dists.filter(d => typeof d === 'number').map(d => d.toFixed(3)),
  requestBody: JSON.stringify({
    model: 'qwen3:30b-a3b-instruct-2507-q8_0',
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ],
    temperature: 0.2,
    max_tokens: 1200,
    stream: false
  })
};

// ═══════════════════════════════════════════════════════
// Step 7: Parse LLM Result
// spaeter pruefen kann ob das RAG korrekt war
// ═══════════════════════════════════════════════════════
const llmResp = $input.item.json;
const fact = $('05 - Parse RAG + Build LLM Request').item.json;

let answer = (llmResp.choices?.[0]?.message?.content || '')
  .replace(/<think>[\s\S]*?<\/think>/g, '')
  .trim();

return {
  id: fact.id,
  kategorie: fact.kategorie,
  aspekt: fact.aspekt,
  hmr: fact.hmr,
  vergleich_aus_rag: answer,
  ragChunkCount: fact.ragChunkCount,
  ragDistances: fact.ragDistances,
  tokens: llmResp.usage?.total_tokens || 0
};

// ═══════════════════════════════════════════════════════
// Step 10: Build Final Synthesis
// Sammelt ALLE Einzelvergleiche und baut den
// finalen LLM-Request fuer die Gesamtgegenueberstellung
// ═══════════════════════════════════════════════════════
const allItems = $input.all();
const results = allItems.map(item => item.json);

const comparisonSections = results.map(r => {
  return '## ' + r.id + '. ' + r.kategorie + ' - ' + r.aspekt + '\n\n' +
    '**HanseMerkur (HMR):** ' + r.hmr + '\n\n' +
    '**ERGO laut RAG-Analyse:**\n' + r.vergleich_aus_rag + '\n\n' +
    '*RAG Chunks: ' + r.ragChunkCount + ' | Distances: ' + (r.ragDistances || []).join(', ') + '*\n';
}).join('\n---\n\n');

const systemPrompt = 'Du bist ein Versicherungsexperte der HanseMerkur. ' +
  'Du erstellst eine Executive Summary eines AVB-Vergleichs zwischen der ' +
  'HanseMerkur Seminar-Ruecktrittsversicherung und der ERGO Seminar-Versicherung.\n\n' +
  'Die Einzelvergleiche basieren auf einer RAG-Analyse der ERGO AVB-Dokumente. ' +
  '' +
  '## Aufgabe:\n' +
  'Erstelle basierend auf den Einzelvergleichen eine strukturierte Gegenueberstellung mit:\n\n' +
  '1. **Executive Summary** (3-5 Saetze Gesamtbewertung)\n' +
  '2. **Vorteile HanseMerkur** (Bullet-Liste: wo HMR besser ist, mit konkreten Details)\n' +
  '3. **Vorteile ERGO** (Bullet-Liste: wo ERGO besser ist, mit konkreten Details)\n' +
  '4. **Gleichwertige Leistungen** (wo beide aehnlich sind)\n' +
  '5. **Kritische Unterschiede** (die wichtigsten Differenzen fuer die Kundenberatung)\n' +
  '6. **Handlungsempfehlung fuer Produktmanagement** (wo sollte HMR nachbessern?)\n' +
  '7. **RAG-Qualitaetsbericht** (Welche Aspekte konnten gut aus den AVB ermittelt werden? ' +
  'Welche Aspekte konnten nicht aus den AVB ermittelt werden?)\n\n' +
  'Formatiere als Markdown. Sei praezise und faktenbasiert. ' +
  'Unterscheide klar zwischen Fakten aus den AVB und eigenen Bewertungen.';

const userPrompt = 'Hier sind die ' + results.length + ' Einzelvergleiche ' +
  '(jeweils mit RAG-Ergebnis):\n\n' +
  comparisonSections + '\n\n' +
  'Erstelle bitte die Gesamtgegenueberstellung.';

return [{
  json: {
    allResults: results,
    resultCount: results.length,
    requestBody: JSON.stringify({
      model: 'qwen3:30b-a3b-instruct-2507-q8_0',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ],
      temperature: 0.3,
      max_tokens: 4000,
      stream: false
    })
  }
}];

// ═══════════════════════════════════════════════════════
// Step 12: Parse Final Synthesis + Build Output
// ═══════════════════════════════════════════════════════
const llmResp = $input.item.json;
const synthData = $('10 - Build Synthese-Request').item.json;

let synthesis = (llmResp.choices?.[0]?.message?.content || '')
  .replace(/<think>[\s\S]*?<\/think>/g, '')
  .trim();

const usage = llmResp.usage || {};

return {
  gesamtvergleich: synthesis,
  einzelvergleiche: synthData.allResults,
  anzahlFakten: synthData.resultCount,
  model: llmResp.model || 'qwen3:30b-a3b-instruct-2507-q8_0',
  usage: {
    promptTokens: usage.prompt_tokens || 0,
    completionTokens: usage.completion_tokens || 0,
    totalTokens: usage.total_tokens || 0
  },
  timestamp: new Date().toISOString(),
  status: 'completed'
};

// ═══════════════════════════════════════════════════════
// Step 13: Final Output - Console/Debug Output
// No Teams, no Webhook - just structured result
// ═══════════════════════════════════════════════════════
const data = $input.item.json;

const einzelDetails = (data.einzelvergleiche || []).map(e => {
  return '### ' + e.id + '. ' + e.kategorie + ' - ' + e.aspekt + '\n' +
    '| Aspekt | HanseMerkur |\n' +
    '|--------|-------------|\n' +
    '| Leistung | ' + e.hmr + ' |\n\n' +
    '**RAG-basierter Vergleich:**\n' + e.vergleich_aus_rag + '\n\n' +
    '*RAG Chunks: ' + e.ragChunkCount +
    ' | Distances: ' + (e.ragDistances || []).join(', ') +
    ' | Tokens: ' + e.tokens + '*\n';
}).join('\n---\n\n');

const fullReport = '# AVB-Vergleich: HanseMerkur vs. ERGO Seminarversicherung\n\n' +
  '**Erstellt:** ' + data.timestamp + '\n' +
  '**Modell:** ' + data.model + '\n' +
  '**Verglichene Fakten:** ' + data.anzahlFakten + '\n' +
  '**Gesamt-Tokens Synthese:** ' + data.usage.totalTokens + '\n' +
  '**ERGO-Datenquelle:** RAG Collection 32c26a09-6c8c-449c-a060-1146f20c0322\n\n' +
  '---\n\n' +
  '# Executive Summary und Gegenueberstellung\n\n' +
  data.gesamtvergleich + '\n\n' +
  '---\n\n' +
  '# Einzelvergleiche (RAG-basiert)\n\n' +
  einzelDetails;

return {
  report: fullReport,
  gesamtvergleich: data.gesamtvergleich,
  einzelvergleiche: data.einzelvergleiche,
  meta: {
    anzahlFakten: data.anzahlFakten,
    model: data.model,
    usage: data.usage,
    timestamp: data.timestamp,
    status: data.status,
    ergo_source: 'RAG Collection 32c26a09-6c8c-449c-a060-1146f20c0322'
  }
};
